func:
if (!global.get('agrocadenas')) global.set('agrocadenas', []);
if (!global.get('usuarios')) global.set('usuarios', []);
if (!global.get('roles')) global.set('roles', [{id:'1',nombre:'Admin',fecha_creacion:new Date().toISOString(),permisos:[]},{id:'2',nombre:'Invitado',fecha_creacion:new Date().toISOString(),permisos:[]}]);
if (!global.get('permisos')) global.set('permisos', [{id:'1',nombre:'Ver',fecha_creacion:new Date().toISOString()},{id:'2',nombre:'Editar',fecha_creacion:new Date().toISOString()},{id:'3',nombre:'Eliminar',fecha_creacion:new Date().toISOString()}]);
if (!global.get('tiposUsuario')) global.set('tiposUsuario', [{id:'1',nombre:'Administrador'},{id:'2',nombre:'Operador'},{id:'3',nombre:'Invitado'}]);
if (!global.get('tiposParticipante')) global.set('tiposParticipante', ['Productor','Distribuidor','Comercializador','Consumidor']);
if (!global.get('tiposProyeccion')) global.set('tiposProyeccion', ['Anual','Semestral','Trimestral']);
if (!global.get('tiposReporte')) global.set('tiposReporte', ['Operativo','Financiero','Estadístico']);
if (!global.get('modulos')) global.set('modulos', []);
if (!global.get('paginas')) global.set('paginas', []);
node.status({fill:'green',shape:'dot',text:'Storage inicializado'});
return null;

var lista = global.get('agrocadenas') || [];
var nueva = {id: Date.now().toString(), nombre: msg.payload.nombre, descripcion: msg.payload.descripcion || '', estado: msg.payload.estado || 'Activo', etapas: [], fecha_creacion: new Date().toISOString()};
lista.push(nueva);
global.set('agrocadenas', lista);
msg.payload = '✅ AgroCadena "' + nueva.nombre + '" registrada con ID ' + nueva.id;
return msg;

var lista = global.get('agrocadenas') || [];
msg.payload = lista.map(function(a){return {ID:a.id, Nombre:a.nombre, Descripción:a.descripcion, Estado:a.estado, Etapas:a.etapas.length, Creado:a.fecha_creacion};});
return msg;

var lista = global.get('agrocadenas') || [];
var cadena = lista.find(function(a){return a.id === msg.payload.agrocadena_id;});
if (!cadena) { msg.payload = '❌ No se encontró AgroCadena con ID ' + msg.payload.agrocadena_id; return msg; }
var etapa = {id: Date.now().toString(), nombre: msg.payload.nombre, descripcion: msg.payload.descripcion || ''};
cadena.etapas.push(etapa);
global.set('agrocadenas', lista);
msg.payload = '✅ Etapa "' + etapa.nombre + '" agregada a "' + cadena.nombre + '"';
return msg;

var lista = global.get('usuarios') || [];
var existe = lista.find(function(u){return u.usuario === msg.payload.usuario;});
if (existe) { msg.payload = '❌ El usuario "' + msg.payload.usuario + '" ya existe'; return msg; }
var nuevo = {id: Date.now().toString(), usuario: msg.payload.usuario, nombre: msg.payload.nombre, apellido: msg.payload.apellido, tipo_usuario: msg.payload.tipo_usuario, clave: msg.payload.clave, hora_registro: new Date().toLocaleTimeString(), fecha_registro: new Date().toLocaleDateString(), estado: 'Activo'};
lista.push(nuevo);
global.set('usuarios', lista);
msg.payload = '✅ Usuario "' + nuevo.usuario + '" registrado correctamente';
return msg;

var lista = global.get('usuarios') || [];
var roles = global.get('roles') || [];
msg.payload = lista.map(function(u){var rol = roles.find(function(r){return r.id === u.rol_id;});return {ID:u.id, Usuario:u.usuario, Nombre:u.nombre+' '+u.apellido, Tipo:u.tipo_usuario, Rol:rol?rol.nombre:'-', Estado:u.estado, Registro:u.fecha_registro};});
return msg;

var usuarios = global.get('usuarios') || [];
var roles = global.get('roles') || [];
var usuario = usuarios.find(function(u){return u.id === msg.payload.usuario_id;});
if (!usuario) { msg.payload = '❌ No se encontró usuario con ID ' + msg.payload.usuario_id; return msg; }
var rol = roles.find(function(r){return r.id === msg.payload.rol_id;});
if (!rol) { msg.payload = '❌ No se encontró rol con ID ' + msg.payload.rol_id; return msg; }
usuario.rol_id = rol.id;
global.set('usuarios', usuarios);
msg.payload = '✅ Rol "' + rol.nombre + '" asignado a "' + usuario.usuario + '"';
return msg;

var usuarios = global.get('usuarios') || [];
var usuario = usuarios.find(function(u){return u.id === msg.payload.usuario_id;});
if (!usuario) { msg.payload = '❌ No se encontró usuario con ID ' + msg.payload.usuario_id; return msg; }
var estadosValidos = ['Activo','Inactivo'];
if (estadosValidos.indexOf(msg.payload.estado) === -1) { msg.payload = '❌ Estado no válido. Use: Activo o Inactivo'; return msg; }
var estadoAnterior = usuario.estado;
usuario.estado = msg.payload.estado;
global.set('usuarios', usuarios);
msg.payload = '✅ Estado de "' + usuario.usuario + '" cambiado de ' + estadoAnterior + ' a ' + usuario.estado;
return msg;

var lista = global.get('roles') || [];
var nuevo = {id: Date.now().toString(), nombre: msg.payload.nombre, fecha_creacion: new Date().toISOString()};
lista.push(nuevo);
global.set('roles', lista);
msg.payload = '✅ Rol "' + nuevo.nombre + '" creado';
return msg;

var roles = global.get('roles') || [];
var permisos = global.get('permisos') || [];
msg.payload = roles.map(function(r){var permisosNombres = (r.permisos||[]).map(function(pid){var p=permisos.find(function(x){return x.id===pid;});return p?p.nombre:pid;}).join(', ');return {ID:r.id, Nombre:r.nombre, Permisos:permisosNombres||'-', Creado:r.fecha_creacion};});
return msg;

var lista = global.get('permisos') || [];
var existe = lista.find(function(p){return p.nombre.toLowerCase() === msg.payload.nombre.toLowerCase();});
if (existe) { msg.payload = '❌ El permiso "' + msg.payload.nombre + '" ya existe'; return msg; }
var nuevo = {id: Date.now().toString(), nombre: msg.payload.nombre, fecha_creacion: new Date().toISOString()};
lista.push(nuevo);
global.set('permisos', lista);
msg.payload = '✅ Permiso "' + nuevo.nombre + '" creado con ID ' + nuevo.id;
return msg;

var permisos = global.get('permisos') || [];
msg.payload = permisos.map(function(p){return {ID:p.id, Nombre:p.nombre, Creado:p.fecha_creacion};});
return msg;

var roles = global.get('roles') || [];
var permisos = global.get('permisos') || [];
var rol = roles.find(function(r){return r.id === msg.payload.rol_id;});
if (!rol) { msg.payload = '❌ No se encontró rol con ID ' + msg.payload.rol_id; return msg; }
var permiso = permisos.find(function(p){return p.id === msg.payload.permiso_id;});
if (!permiso) { msg.payload = '❌ No se encontró permiso con ID ' + msg.payload.permiso_id; return msg; }
if (!rol.permisos) rol.permisos = [];
var yaAsignado = rol.permisos.find(function(p){return p === msg.payload.permiso_id;});
if (yaAsignado) { msg.payload = '❌ El permiso "' + permiso.nombre + '" ya está asignado al rol "' + rol.nombre + '"'; return msg; }
rol.permisos.push(permiso.id);
global.set('roles', roles);
msg.payload = '✅ Permiso "' + permiso.nombre + '" asignado al rol "' + rol.nombre + '"';
return msg;

var lista = global.get('modulos') || [];
var existe = lista.find(function(m){return m.nombre.toLowerCase() === msg.payload.nombre.toLowerCase();});
if (existe) { msg.payload = '❌ El módulo "' + msg.payload.nombre + '" ya existe'; return msg; }
var nuevo = {id: Date.now().toString(), nombre: msg.payload.nombre};
lista.push(nuevo);
global.set('modulos', lista);
msg.payload = '✅ Módulo "' + nuevo.nombre + '" creado con ID ' + nuevo.id;
return msg;

var lista = global.get('modulos') || [];
msg.payload = lista.map(function(m){return {ID:m.id, Nombre:m.nombre};});
return msg;

var lista = global.get('paginas') || [];
var existe = lista.find(function(p){return p.ruta.toLowerCase() === msg.payload.ruta.toLowerCase();});
if (existe) { msg.payload = '❌ Ya existe una página con ruta "' + msg.payload.ruta + '"'; return msg; }
var nueva = {id: Date.now().toString(), nombre: msg.payload.nombre, ruta: msg.payload.ruta, opciones: []};
lista.push(nueva);
global.set('paginas', lista);
msg.payload = '✅ Página "' + nueva.nombre + '" creada con ID ' + nueva.id;
return msg;

var lista = global.get('paginas') || [];
msg.payload = lista.map(function(p){return {ID:p.id, Nombre:p.nombre, Ruta:p.ruta, Opciones:p.opciones.length};});
return msg;

var paginas = global.get('paginas') || [];
var pagina = paginas.find(function(p){return p.id === msg.payload.pagina_id;});
if (!pagina) { msg.payload = '❌ No se encontró página con ID ' + msg.payload.pagina_id; return msg; }
var nueva = {id: Date.now().toString(), nombre: msg.payload.nombre, url: msg.payload.url, modulo_id: msg.payload.modulo_id || null};
pagina.opciones.push(nueva);
global.set('paginas', paginas);
msg.payload = '✅ Opción "' + nueva.nombre + '" agregada a la página "' + pagina.nombre + '"';
return msg;

var msgs = [];
var tiposUsr = (global.get('tiposUsuario')||[]).map(function(t){return typeof t === 'object' ? t.nombre : t;});
msgs[0] = {payload: tiposUsr.join(', ')};
msgs[1] = {payload: (global.get('tiposParticipante')||[]).join(', ')};
msgs[2] = {payload: (global.get('tiposProyeccion')||[]).join(', ')};
msgs[3] = {payload: (global.get('tiposReporte')||[]).join(', ')};
return msgs;

var cat = msg.payload.catalogo;
var val = msg.payload.valor;
var validos = ['tiposUsuario','tiposParticipante','tiposProyeccion','tiposReporte'];
if (validos.indexOf(cat) === -1) { msg.payload = '❌ Catálogo no válido. Use: ' + validos.join(', '); return msg; }
var lista = global.get(cat) || [];
if (lista.indexOf(val) >= 0) { msg.payload = '❌ "' + val + '" ya existe en ' + cat; return msg; }
lista.push(val);
global.set(cat, lista);
msg.payload = '✅ "' + val + '" agregado a ' + cat;
return msg;
